    #[test]
    fn replaces_changed_bytes_no_ops_identical_bytes_and_reconciles_known_stale_files() {
        block_on_inline(async {
            let output_key = FileKey::parse("target/jals/build/rhai/out/A.java").unwrap();
            let modified_key = FileKey::parse("target/jals/build/rhai/out/modified.txt").unwrap();
            let mut storage = storage(
                r#"
                    output.write_text("A.java", "new");
                    output.write_text("modified.txt", "generated");
                "#,
                [Entry::File(output_key.clone(), b"old".to_vec())],
            );
            let mut session = BuildScriptSession::new();
            let first = run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut session,
            )
            .await
            .unwrap();
            assert_eq!(storage.view().file(&output_key).unwrap().bytes(), b"new");
            let after_replace = first.revision;

            let second = run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut session,
            )
            .await
            .unwrap();
            assert_eq!(second.revision, after_replace);

            let script_key = FileKey::parse("build.rhai").unwrap();
            let revision = storage.revision();
            let mut transaction = storage.transaction(revision).unwrap();
            transaction
                .replace_file(
                    script_key,
                    br#"output.write_text("B.java", "next");"#.to_vec(),
                )
                .unwrap();
            transaction
                .replace_file(modified_key.clone(), b"user change".to_vec())
                .unwrap();
            transaction.commit().await.unwrap();
            run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut session,
            )
            .await
            .unwrap();
            assert!(storage.view().file(&output_key).is_err());
            assert_eq!(
                storage.view().file(&modified_key).unwrap().bytes(),
                b"user change"
            );
            assert_eq!(
                storage
                    .view()
                    .file(&FileKey::parse("target/jals/build/rhai/out/B.java").unwrap())
                    .unwrap()
                    .bytes(),
                b"next"
            );
        });
    }

    #[test]
