            first_environment.insert("VALUE", "first");
            run(
                &mut storage,
                &first_environment,
                &BuildScriptLimits::default(),
                &mut BuildScriptSession::new(),
            )
            .await
            .unwrap();
            let tree = storage.view().tree().clone();
            let cache = storage.artifacts().backend().clone();
            let mut storage = ProjectStorage::open(MemorySource::new(tree), cache, Exec::inline())
                .await
                .unwrap();
            let revision = storage.revision();

            let mut second_environment = BuildScriptEnvironment::new();
            second_environment.insert("VALUE", "would-only-appear-after-evaluation");
