    #[test]
    fn explicit_rerun_files_narrow_the_project_fingerprint() {
        block_on_inline(async {
            let mut storage = storage(
                r#"
                    build.rerun_if_changed("watched.txt");
                    output.write_text("value.txt", project.read_text("ignored.txt"));
                "#,
                [file("watched.txt", "one"), file("ignored.txt", "first")],
            );
            let output_key = FileKey::parse("target/jals/build/rhai/out/value.txt").unwrap();
            run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut BuildScriptSession::new(),
            )
            .await
            .unwrap();

            let ignored_revision = replace(&mut storage, "ignored.txt", b"second").await;
            let hit = run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut BuildScriptSession::new(),
            )
            .await
            .unwrap();
            assert_eq!(hit.revision, ignored_revision);
            assert_eq!(storage.view().file(&output_key).unwrap().bytes(), b"first");

            let watched_revision = replace(&mut storage, "watched.txt", b"two").await;
            let miss = run(
                &mut storage,
                &BuildScriptEnvironment::new(),
                &BuildScriptLimits::default(),
                &mut BuildScriptSession::new(),
            )
            .await
            .unwrap();
            assert_ne!(miss.revision, watched_revision);
            assert_eq!(storage.view().file(&output_key).unwrap().bytes(), b"second");
        });
    }

